shellProfiles.pwsh:
# Load local .env if present
if (Test-Path "$PSScriptRoot/../../.env") {
  foreach ($line in Get-Content "$PSScriptRoot/../../.env") {
    if ($line -match '^\s*#' -or $line -notmatch '=') { continue }
    $parts = $line -split '=', 2
    if (-not $env:$($parts[0])) { $env:$($parts[0]) = $parts[1] }
  }
}
